{
var seed = GetInt(parameters, "seed", context.Seed);
        var scale = GetFloat(parameters, "scale", 5f);
        var octaves = GetInt(parameters, "octaves", 3);
        var persistence = GetFloat(parameters, "persistence", 0.5f);
        var lacunarity = GetFloat(parameters, "lacunarity", 2f);
        var noiseType = GetChoice(parameters, "type", "Value");
        var brightness = GetFloat(parameters, "brightness", 0f);
        var contrast = GetFloat(parameters, "contrast", 0f);
        var offsetX = GetFloat(parameters, "offsetX", 0f);
        var offsetY = GetFloat(parameters, "offsetY", 0f);
        var threshLow = GetFloat(parameters, "lowThreshold", 0f);
        var threshHigh = GetFloat(parameters, "highThreshold", 1f);
        var invert = GetBool(parameters, "invert");
        var colorOutput = GetBool(parameters, "colorOutput");

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);
        buffer.ParallelForEachPixel((x, y) =>
        {
            var nx = (x / (float)size + offsetX) * scale;
            var ny = (y / (float)size + offsetY) * scale;
            var period = Math.Max(1, (int)MathF.Round(scale));

            float v;
            switch (noiseType)
            {
                case "Gradient":
                    v = 0f;
                    float amp = 1f, freq = 1f, maxAmp = 0f;
                    for (var o = 0; o < octaves; o++)
                    {
                        var op = Math.Max(1, (int)MathF.Round(period * freq));
                        v += TileableGradientNoise(nx * freq, ny * freq, op, seed + o * 1013) * amp;
                        maxAmp += amp;
                        amp *= persistence;
                        freq *= lacunarity;
                    }
                    v = maxAmp > 0 ? v / maxAmp : 0.5f;
                    break;

                case "Voronoi":
                    var cellSize = Math.Max(1, size / Math.Max(1, (int)scale));
                    var cellCount = Math.Max(1, size / cellSize);
                    // Apply offset in pixel space so Voronoi position is consistent with other noise types.
                    var vx = x + offsetX * size;
                    var vy = y + offsetY * size;
                    TileableVoronoi(vx, vy, cellSize, cellCount, seed, out var nearest, out _, out _, out _);
                    v = nearest;
                    break;

                case "Ridge":
                    v = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed);
                    v = 1f - MathF.Abs(v * 2f - 1f);
                    break;

                case "Turbulence":
                    v = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed);
                    v = MathF.Abs(v * 2f - 1f);
                    break;

                default: // "Value"
                    v = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed);
                    break;
            }

            v = Math.Clamp(v, 0f, 1f);

            if (colorOutput)
            {
                var vr = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed);
                var vg = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed + 317);
                var vb = TileableFractalNoise(nx, ny, period, octaves, persistence, lacunarity, seed + 631);
                buffer.SetPixel(x, y, vr, vg, vb, 1f);
            }
            else
            {
                buffer.SetPixel(x, y, v, v, v, 1f);
            }
        });

        // Apply post-processing via GPU or CPU fallback.
        if (!GpuProcessor.TryPostProcess(buffer, brightness, contrast, threshLow, threshHigh, invert, colorOutput))
        {
            ApplyPostProcessInPlace(buffer, brightness, contrast, threshLow, threshHigh, invert, colorOutput);
        }

        return buffer;

    /// <summary>
    /// CPU fallback for post-processing. Operates on the buffer in-place.
    /// Mirror of GPU PostProcessInPlace logic.
    /// </summary>
    private static void ApplyPostProcessInPlace(PixelBuffer buffer, float brightness, float contrast,
        float threshLow, float threshHigh, bool invert, bool colorOutput)
    {
        buffer.ParallelForEachPixel((x, y) =>
        {
            var (r, g, b, a) = buffer.GetPixel(x, y);

            if (colorOutput)
            {
                if (threshHigh > threshLow)
                {
                    r = Math.Clamp((r - threshLow) / (threshHigh - threshLow), 0f, 1f);
                    g = Math.Clamp((g - threshLow) / (threshHigh - threshLow), 0f, 1f);
                    b = Math.Clamp((b - threshLow) / (threshHigh - threshLow), 0f, 1f);
                }

                if (MathF.Abs(contrast) > 0.001f)
                {
                    var factor = 1f + contrast;
                    r = (r - 0.5f) * factor + 0.5f;
                    g = (g - 0.5f) * factor + 0.5f;
                    b = (b - 0.5f) * factor + 0.5f;
                }

                r = Math.Clamp(r + brightness, 0f, 1f);
                g = Math.Clamp(g + brightness, 0f, 1f);
                b = Math.Clamp(b + brightness, 0f, 1f);

                if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

                buffer.SetPixel(x, y, r, g, b, a);
            }
            else
            {
                // All channels are identical for grayscale mode; sample r as the value.
                var v = r;
                if (threshHigh > threshLow)
                    v = Math.Clamp((v - threshLow) / (threshHigh - threshLow), 0f, 1f);

                if (MathF.Abs(contrast) > 0.001f)
                {
                    var factor = 1f + contrast;
                    v = (v - 0.5f) * factor + 0.5f;
                }

                v = Math.Clamp(v + brightness, 0f, 1f);
                if (invert) v = 1f - v;

                buffer.SetPixel(x, y, v, v, v, a);
            }
        });
    }
}
